class BackgroundTaskService : IntentService("BackgroundTaskService") {

    override fun onHandleIntent(intent: Intent?) {
        if (intent != null) {
            val taskType = intent.getStringExtra("task_type")

            when (taskType) {
                "data_sync" -> {
                    // Perform data synchronization operations
                    Log.d("BackgroundTaskService", "Syncing data...")
                }
                "cleanup" -> {
                    // Perform cleanup operations
                    Log.d("BackgroundTaskService", "Cleaning up...")
                }
            }
        }
    }
